      .setTitle('YARA Gen')
      .setColor(0x222222)
      .setDescription(`Regra gerada: \`${ruleName}\`\nStrings: ${picked.length}\nArquivo: \`${outPath}\``);

    const file = new AttachmentBuilder(Buffer.from(yara, 'utf-8'), { name: `${ruleName}.yara` });
